const e=JSON.parse('{"key":"v-2076368e","path":"/posts/104.CRC16-ITU%E7%9A%84%E8%AE%A1%E7%AE%97%E7%AE%97%E6%B3%95.html","title":"CRC-ITU的计算算法","lang":"zh-CN","frontmatter":{"icon":"pen-to-square","comment":false,"date":"2021-12-13T22:12:00.000Z","author":"Roger","category":["总结","学习总结"],"tag":["CRC16-ITU"],"description":"CRC-ITU的计算算法 CRC-ITU的计算算法如下： a.寄存器组初始化为全\\"1\\"(0xFFFF)。 b.寄存器组向右移动一个字节。 c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。 d.索引所指的表值与寄存器组做异或运算。 f.数据指针加1，如果数据没有全部处理完，则重复步骤b。 g.寄存器组取反，得到CRC，附加在数据之后。 CRC-ITU的验证算法如下： a.寄存器组初始化为全\\"1\\"(0xFFFF)。 b.寄存器组向右移动一个字节。 c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。 d.索引所指的表值与寄存器组做异或运算。 e.数据指针加1，如果数据没有全部处理完，则重复步骤b (数据包括CRC的两个字节)。 f.寄存器组的值是否等于“Magic Value”(0xF0B8)，若相等则通过，否则失败。","head":[["meta",{"property":"og:url","content":"https://roger0x0000.github.io/blog/blog/posts/104.CRC16-ITU%E7%9A%84%E8%AE%A1%E7%AE%97%E7%AE%97%E6%B3%95.html"}],["meta",{"property":"og:site_name","content":"电源知识搬运"}],["meta",{"property":"og:title","content":"CRC-ITU的计算算法"}],["meta",{"property":"og:description","content":"CRC-ITU的计算算法 CRC-ITU的计算算法如下： a.寄存器组初始化为全\\"1\\"(0xFFFF)。 b.寄存器组向右移动一个字节。 c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。 d.索引所指的表值与寄存器组做异或运算。 f.数据指针加1，如果数据没有全部处理完，则重复步骤b。 g.寄存器组取反，得到CRC，附加在数据之后。 CRC-ITU的验证算法如下： a.寄存器组初始化为全\\"1\\"(0xFFFF)。 b.寄存器组向右移动一个字节。 c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。 d.索引所指的表值与寄存器组做异或运算。 e.数据指针加1，如果数据没有全部处理完，则重复步骤b (数据包括CRC的两个字节)。 f.寄存器组的值是否等于“Magic Value”(0xF0B8)，若相等则通过，否则失败。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-10-07T11:25:37.000Z"}],["meta",{"property":"article:author","content":"Roger"}],["meta",{"property":"article:tag","content":"CRC16-ITU"}],["meta",{"property":"article:published_time","content":"2021-12-13T22:12:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-10-07T11:25:37.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"CRC-ITU的计算算法\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-12-13T22:12:00.000Z\\",\\"dateModified\\":\\"2023-10-07T11:25:37.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Roger\\"}]}"]]},"headers":[],"git":{"createdTime":1696677937000,"updatedTime":1696677937000,"contributors":[{"name":"Roger0x0000","email":"Roger0x0000@outlook.com","commits":1}]},"readingTime":{"minutes":3.02,"words":905},"filePathRelative":"posts/104.CRC16-ITU的计算算法.md","localizedDate":"2021年12月13日","excerpt":"<h1> CRC-ITU的计算算法</h1>\\n<p>CRC-ITU的计算算法如下：</p>\\n<ul>\\n<li>a.寄存器组初始化为全\\"1\\"(0xFFFF)。</li>\\n<li>b.寄存器组向右移动一个字节。</li>\\n<li>c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。</li>\\n<li>d.索引所指的表值与寄存器组做异或运算。</li>\\n<li>f.数据指针加1，如果数据没有全部处理完，则重复步骤b。</li>\\n<li>g.寄存器组取反，得到CRC，附加在数据之后。</li>\\n</ul>\\n<p>CRC-ITU的验证算法如下：</p>\\n<ul>\\n<li>a.寄存器组初始化为全\\"1\\"(0xFFFF)。</li>\\n<li>b.寄存器组向右移动一个字节。</li>\\n<li>c.刚移出的那个字节与数据字节进行异或运算，得出一个指向值表的索引。</li>\\n<li>d.索引所指的表值与寄存器组做异或运算。</li>\\n<li>e.数据指针加1，如果数据没有全部处理完，则重复步骤b (数据包括CRC的两个字节)。</li>\\n<li>f.寄存器组的值是否等于“Magic Value”(0xF0B8)，若相等则通过，否则失败。</li>\\n</ul>\\n","autoDesc":true}');export{e as data};
